// AppConfiguration.swift
import Foundation

/// SECURITY: Keys are loaded from a plist file NOT checked into source control.
/// For the demo build, the plist is embedded in the app bundle.
/// For production, these would come from a secure backend or keychain.
///
/// WHY NOT HARDCODE: Even "test" keys embedded in source code end up in:
/// - Git history (forever, even after "replacing")
/// - Compiled binaries (extractable with `strings` command)
/// - CI/CD logs, crash reports, etc.
///
/// This approach keeps the demo frictionless while maintaining security hygiene.
struct AppConfiguration {
    
    enum ConfigError: Error, LocalizedError {
        case missingPlist
        case missingKey(String)
        
        var errorDescription: String? {
            switch self {
            case .missingPlist:
                return "Configuration file not found. See README for setup."
            case .missingKey(let key):
                return "Missing configuration key: \(key)"
            }
        }
    }
    
    static let shared = AppConfiguration()
    
    private let config: [String: Any]
    
    init() {
        // Load from Secrets.plist (included in bundle but .gitignored)
        guard let path = Bundle.main.path(forResource: "Secrets", ofType: "plist"),
              let dict = NSDictionary(contentsOfFile: path) as? [String: Any] else {
            // Fallback: check for environment variables (CI/CD friendly)
            var fallback: [String: Any] = [:]
            if let gmaps = ProcessInfo.processInfo.environment["GOOGLE_MAPS_API_KEY"] {
                fallback["GoogleMapsAPIKey"] = gmaps
            }
            if let stripe = ProcessInfo.processInfo.environment["STRIPE_PUBLISHABLE_KEY"] {
                fallback["StripePublishableKey"] = stripe
            }
            self.config = fallback
            return
        }
        self.config = dict
    }
    
    var googleMapsAPIKey: String {
        get throws {
            guard let key = config["GoogleMapsAPIKey"] as? String, !key.isEmpty else {
                throw ConfigError.missingKey("GoogleMapsAPIKey")
            }
            return key
        }
    }
    
    var stripePublishableKey: String {
        get throws {
            guard let key = config["StripePublishableKey"] as? String, !key.isEmpty else {
                throw ConfigError.missingKey("StripePublishableKey")
            }
            return key
        }
    }
}


