// AppDelegate.swift
import UIKit
import GoogleMaps
import StripePaymentSheet

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication,
                     didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        do {
            let config = AppConfiguration.shared
            
            // Initialize Google Maps
            GMSServices.provideAPIKey(try config.googleMapsAPIKey)
            
            // Initialize Stripe
            StripeAPI.defaultPublishableKey = try config.stripePublishableKey
            
        } catch {
            print("⚠️ Configuration Error: \(error.localizedDescription)")
            print("📋 Create a Secrets.plist file with your API keys. See AppConfiguration.swift for details.")
            // In demo mode, we'll show an alert on the first screen
        }
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let tabBar = MainTabBarController()
        window?.rootViewController = tabBar
        window?.makeKeyAndVisible()
        
        return true
    }
}


