// MapViewController.swift
import UIKit
import GoogleMaps

class MapViewController: UIViewController {
    
    private var mapView: GMSMapView!
    private var locations = DemoData.locations
    private var categoryFilter: ServiceLocation.ServiceCategory?
    private var filterCollectionView: UICollectionView!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Explore"
        navigationController?.navigationBar.prefersLargeTitles = true
        
        setupMap()
        setupFilterBar()
        addMarkers()
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7949,
            longitude: -122.4094,
            zoom: 13.5
        )
        
        let mapViewOptions = GMSMapViewOptions()
        mapViewOptions.camera = camera
        mapViewOptions.frame = view.bounds
        
        mapView = GMSMapView(options: mapViewOptions)
        mapView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        mapView.delegate = self
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        
        // Apply custom map style
        if let styleURL = Bundle.main.url(forResource: "MapStyle", withExtension: "json"),
           let style = try? GMSMapStyle(contentsOfFileURL: styleURL) {
            mapView.mapStyle = style
        }
        
        view.addSubview(mapView)
    }
    
    private func setupFilterBar() {
        let layout = UICollectionViewFlowLayout()
        layout.scrollDirection = .horizontal
        layout.estimatedItemSize = UICollectionViewFlowLayout.automaticSize
        layout.minimumInteritemSpacing = 8
        layout.sectionInset = UIEdgeInsets(top: 0, left: 16, bottom: 0, right: 16)
        
        filterCollectionView = UICollectionView(frame: .zero, collectionViewLayout: layout)
        filterCollectionView.translatesAutoresizingMaskIntoConstraints = false
        filterCollectionView.backgroundColor = .clear
        filterCollectionView.showsHorizontalScrollIndicator = false
        filterCollectionView.delegate = self
        filterCollectionView.dataSource = self
        filterCollectionView.register(FilterCell.self, forCellWithReuseIdentifier: "FilterCell")
        
        let blurEffect = UIBlurEffect(style: .systemMaterial)
        let blurView = UIVisualEffectView(effect: blurEffect)
        blurView.translatesAutoresizingMaskIntoConstraints = false
        blurView.layer.cornerRadius = 20
        blurView.clipsToBounds = true
        
        view.addSubview(blurView)
        view.addSubview(filterCollectionView)
        
        NSLayoutConstraint.activate([
            blurView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 8),
            blurView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 8),
            blurView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -8),
            blurView.heightAnchor.constraint(equalToConstant: 50),
            
            filterCollectionView.topAnchor.constraint(equalTo: blurView.topAnchor),
            filterCollectionView.leadingAnchor.constraint(equalTo: blurView.leadingAnchor),
            filterCollectionView.trailingAnchor.constraint(equalTo: blurView.trailingAnchor),
            filterCollectionView.bottomAnchor.constraint(equalTo: blurView.bottomAnchor)
        ])
    }
    
    private func addMarkers() {
        mapView.clear()
        
        let filteredLocations = categoryFilter == nil ? locations : locations.filter { $0.category == categoryFilter }
        
        for location in filteredLocations {
            let marker = GMSMarker(position: location.coordinate)
            marker.title = location.name
            marker.snippet = "\(location.category.rawValue) • \(location.priceRange) • ⭐ \(location.rating)"
            marker.userData = location
            marker.icon = GMSMarker.markerImage(with: location.category.color)
            marker.appearAnimation = .pop
            marker.map = mapView
        }
    }
}

// MARK: - GMSMapViewDelegate
extension MapViewController: GMSMapViewDelegate {
    
    func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
        guard let location = marker.userData as? ServiceLocation else { return false }
        
        let detailVC = LocationDetailViewController(location: location)
        let nav = UINavigationController(rootViewController: detailVC)
        
        if let sheet = nav.sheetPresentationController {
            sheet.detents = [.medium(), .large()]
            sheet.prefersGrabberVisible = true
        }
        
        present(nav, animated: true)
        return true
    }
    
    func mapView(_ mapView: GMSMapView, markerInfoWindow marker: GMSMarker) -> UIView? {
        guard let location = marker.userData as? ServiceLocation else { return nil }
        
        let infoView = CustomInfoWindowView(frame: CGRect(x: 0, y: 0, width: 250, height: 80))
        infoView.configure(with: location)
        return infoView
    }
}

// MARK: - UICollectionView
extension MapViewController: UICollectionViewDelegate, UICollectionViewDataSource {
    
    func collectionView(_ collectionView: UICollectionView, numberOfItemsInSection section: Int) -> Int {
        return ServiceLocation.ServiceCategory.allCases.count + 1 // +1 for "All"
    }
    
    func collectionView(_ collectionView: UICollectionView, cellForItemAt indexPath: IndexPath) -> UICollectionViewCell {
        let cell = collectionView.dequeueReusableCell(withReuseIdentifier: "FilterCell", for: indexPath) as! FilterCell
        
        if indexPath.item == 0 {
            cell.configure(title: "All", icon: "square.grid.2x2", isSelected: categoryFilter == nil)
        } else {
            let category = ServiceLocation.ServiceCategory.allCases[indexPath.item - 1]
            cell.configure(title: category.rawValue, icon: category.icon, isSelected: categoryFilter == category)
        }
        
        return cell
    }
    
    func collectionView(_ collectionView: UICollectionView, didSelectItemAt indexPath: IndexPath) {
        if indexPath.item == 0 {
            categoryFilter = nil
        } else {
            categoryFilter = ServiceLocation.ServiceCategory.allCases[indexPath.item - 1]
        }
        
        collectionView.reloadData()
        addMarkers()
        
        // Animate camera to show filtered markers
        if let filter = categoryFilter {
            let filtered = locations.filter { $0.category == filter }
            if let first = filtered.first {
                let camera = GMSCameraPosition.camera(withTarget: first.coordinate, zoom: 14)
                mapView.animate(to: camera)
            }
        }
    }
}


// FilterCell.swift
import UIKit

class FilterCell: UICollectionViewCell {
    
    private let label = UILabel()
    private let iconView = UIImageView()
    private let containerView = UIView()
    
    override init(frame: CGRect) {
        super.init(frame: frame)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        containerView.translatesAutoresizingMaskIntoConstraints = false
        containerView.layer.cornerRadius = 16
        containerView.clipsToBounds = true
        contentView.addSubview(containerView)
        
        let stack = UIStackView(arrangedSubviews: [iconView, label])
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .horizontal
        stack.spacing = 4
        stack.alignment = .center
        containerView.addSubview(stack)
        
        iconView.contentMode = .scaleAspectFit
        iconView.tintColor = .label
        label.font = .systemFont(ofSize: 13, weight: .semibold)
        
        NSLayoutConstraint.activate([
            containerView.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 6),
            containerView.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -6),
            containerView.leadingAnchor.constraint(equalTo: contentView.leadingAnchor),
            containerView.trailingAnchor.constraint(equalTo: contentView.trailingAnchor),
            
            stack.topAnchor.constraint(equalTo: containerView.topAnchor, constant: 6),
            stack.bottomAnchor.constraint(equalTo: containerView.bottomAnchor, constant: -6),
            stack.leadingAnchor.constraint(equalTo: containerView.leadingAnchor, constant: 12),
            stack.trailingAnchor.constraint(equalTo: containerView.trailingAnchor, constant: -12),
            
            iconView.widthAnchor.constraint(equalToConstant: 16),
            iconView.heightAnchor.constraint(equalToConstant: 16)
        ])
    }
    
    func configure(title: String, icon: String, isSelected: Bool) {
        label.text = title
        iconView.image = UIImage(systemName: icon)
        
        if isSelected {
            containerView.backgroundColor = UIColor(red: 0.35, green: 0.47, blue: 1.0, alpha: 1.0)
            label.textColor = .white
            iconView.tintColor = .white
        } else {
            containerView.backgroundColor = .secondarySystemBackground
            label.textColor = .label
            iconView.tintColor = .label
        }
    }
}


