            badgeStack.addArrangedSubview(label)
            stack.addArrangedSubview(badgeStack)
        }
        
        return stack
    }
    
    private func fetchPaymentIntent() {
        // In a real app, this calls YOUR backend which creates a PaymentIntent
        // and returns the clientSecret. Never create PaymentIntents from the client.
        //
        // Demo: We simulate the backend response
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            guard let self = self else { return }
            
            // In production, this would be:
            // let response = await APIClient.createPaymentIntent(amount: self.amount)
            // self.configurePaymentSheet(clientSecret: response.clientSecret)
            
            // For demo, configure PaymentSheet with test configuration
            self.configureDemoPaymentSheet()
        }
    }
    
    private func configureDemoPaymentSheet() {
        // NOTE: In a real implementation, you need a clientSecret from your backend.
        // This demo shows the UI flow. For actual payment testing, you need:
        // 1. A backend endpoint that creates a PaymentIntent via Stripe API
        // 2. The clientSecret returned from that endpoint
        
        // Simulate ready state for demo
        activityIndicator.stopAnimating()
        statusLabel.text = "✅ Secure checkout ready"
        statusLabel.textColor = .systemGreen
        
        UIView.animate(withDuration: 0.3) {
            self.payButton.isEnabled = true
            self.payButton.alpha = 1.0
        }
    }
    
    @objc private func didTapPay() {
        // For a real integration with a backend-provided clientSecret:
        /*
        guard let paymentSheet = paymentSheet else { return }
        paymentSheet.present(from: self) { [weak self] result in
            switch result {
            case .completed:
                self?.handlePaymentSuccess()
            case .canceled:
                self?.statusLabel.text = "Payment cancelled"
            case .failed(let error):
                self?.statusLabel.text = "Payment failed: \(error.localizedDescription)"
            }
        }
        */
        
        // Demo flow: Show a simulated payment UI
        presentDemoPaymentFlow()
    }
    
    private func presentDemoPaymentFlow() {
        let alert = UIAlertController(
            title: "Stripe Payment Demo",
            message: "In the live app, this opens Stripe's native PaymentSheet with Apple Pay, cards, and other payment methods.\n\nAmount: \(String(format: "$%.2f", amount))",
            preferredStyle: .actionSheet
        )
        
        alert.addAction(UIAlertAction(title: "💳 Simulate Successful Payment", style: .default) { [weak self] _ in
            self?.handlePaymentSuccess()
        })
        
        alert.addAction(UIAlertAction(title: " Simulate Apple Pay", style: .default) { [weak self] _ in
            self?.handlePaymentSuccess()
        })
        
        alert.addAction(UIAlertAction(title: "❌ Simulate Failed Payment", style: .destructive) { [weak self] _ in
            self?.handlePaymentFailure()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func handlePaymentSuccess() {
        let successVC = PaymentSuccessViewController(location: location!, amount: amount)
        successVC.modalPresentationStyle = .fullScreen
        present(successVC, animated: true)
    }
    
    private func handlePaymentFailure() {
        statusLabel.text = "❌ Payment failed — please try again"
        statusLabel.textColor = .systemRed
        
        let shake = CAKeyframeAnimation(keyPath: "transform.translation.x")
        shake.timingFunction = CAMediaTimingFunction(name: .linear)
        shake.values = [-10, 10, -8, 8, -5, 5, 0]
        shake.duration = 0.4
        payButton.layer.add(shake, forKey: "shake")
    }
}


