import UIKit

class PaymentSuccessViewController: UIViewController {
    
    private let location: ServiceLocation
    private let amount: Double
    
    init(location: ServiceLocation, amount: Double) {
        self.location = location
        self.amount = amount
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        setupUI()
        animateSuccess()
    }
    
    private func setupUI() {
        let checkmarkContainer = UIView()
        checkmarkContainer.translatesAutoresizingMaskIntoConstraints = false
        checkmarkContainer.backgroundColor = UIColor.systemGreen.withAlphaComponent(0.15)
        checkmarkContainer.layer.cornerRadius = 50
        
        let checkmark = UIImageView(image: UIImage(systemName: "checkmark.circle.fill"))
        checkmark.translatesAutoresizingMaskIntoConstraints = false
        checkmark.tintColor = .systemGreen
        checkmark.contentMode = .scaleAspectFit
        checkmarkContainer.addSubview(checkmark)
        
        let titleLabel = UILabel()
        titleLabel.translatesAutoresizingMaskIntoConstraints = false
        titleLabel.text = "Payment Successful!"
        titleLabel.font = .systemFont(ofSize: 28, weight: .bold)
        titleLabel.textAlignment = .center
        
        let amountLabel = UILabel()
        amountLabel.translatesAutoresizingMaskIntoConstraints = false
        amountLabel.text = String(format: "$%.2f", amount)
        amountLabel.font = .systemFont(ofSize: 36, weight: .heavy)
        amountLabel.textColor = UIColor(red: 0.35, green: 0.47, blue: 1.0, alpha: 1.0)
        amountLabel.textAlignment = .center
        
        let detailLabel = UILabel()
        detailLabel.translatesAutoresizingMaskIntoConstraints = false
        detailLabel.text = "Booking confirmed for\n\(location.name)"
        detailLabel.font = .systemFont(ofSize: 16, weight: .medium)
        detailLabel.textColor = .secondaryLabel
        detailLabel.textAlignment = .center
        detailLabel.numberOfLines = 0
        
        // Confirmation details card
        let confirmCard = UIView()
        confirmCard.translatesAutoresizingMaskIntoConstraints = false
        confirmCard.backgroundColor = .secondarySystemBackground
        confirmCard.layer.cornerRadius = 16
        
        let confirmationID = UILabel()
        confirmationID.translatesAutoresizingMaskIntoConstraints = false
        confirmationID.text = "Confirmation #: \(UUID().uuidString.prefix(8).uppercased())"
        confirmationID.font = .monospacedSystemFont(ofSize: 14, weight: .medium)
        confirmationID.textAlignment = .center
        confirmCard.addSubview(confirmationID)
        
        let dateLabel = UILabel()
        dateLabel.translatesAutoresizingMaskIntoConstraints = false
        let formatter = DateFormatter()
        formatter.dateStyle = .full
        formatter.timeStyle = .short
        dateLabel.text = formatter.string(from: Date())
        dateLabel.font = .systemFont(ofSize: 13, weight: .regular)
        dateLabel.textColor = .secondaryLabel
        dateLabel.textAlignment = .center
        confirmCard.addSubview(dateLabel)
        
        // Done button
        let doneButton = UIButton(type: .system)
        doneButton.translatesAutoresizingMaskIntoConstraints = false
        doneButton.setTitle("Done", for: .normal)
        doneButton.titleLabel?.font = .systemFont(ofSize: 17, weight: .bold)
        doneButton.setTitleColor(.white, for: .normal)
        doneButton.backgroundColor = UIColor(red: 0.35, green: 0.47, blue: 1.0, alpha: 1.0)
        doneButton.layer.cornerRadius = 14
        doneButton.addTarget(self, action: #selector(done), for: .touchUpInside)
        
        let shareButton = UIButton(type: .system)
        shareButton.translatesAutoresizingMaskIntoConstraints = false
        shareButton.setTitle("Share Receipt", for: .normal)
        shareButton.titleLabel?.font = .systemFont(ofSize: 15, weight: .medium)
        
        [checkmarkContainer, titleLabel, amountLabel, detailLabel, confirmCard, doneButton, shareButton].forEach {
            view.addSubview($0)
        }
        
        NSLayoutConstraint.activate([
            checkmarkContainer.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 60),
            checkmarkContainer.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            checkmarkContainer.widthAnchor.constraint(equalToConstant: 100),
            checkmarkContainer.heightAnchor.constraint(equalToConstant: 100),
            
            checkmark.centerXAnchor.constraint(equalTo: checkmarkContainer.centerXAnchor),
            checkmark.centerYAnchor.constraint(equalTo: checkmarkContainer.centerYAnchor),
            checkmark.widthAnchor.constraint(equalToConstant: 60),
            checkmark.heightAnchor.constraint(equalToConstant: 60),
            
            titleLabel.topAnchor.constraint(equalTo: checkmarkContainer.bottomAnchor, constant: 24),
            titleLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            amountLabel.topAnchor.constraint(equalTo: titleLabel.bottomAnchor, constant: 8),
            amountLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            detailLabel.topAnchor.constraint(equalTo: amountLabel.bottomAnchor, constant: 12),
            detailLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            detailLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 40),
            detailLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -40),
            
            confirmCard.topAnchor.constraint(equalTo: detailLabel.bottomAnchor, constant: 30),
            confirmCard.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            confirmCard.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24),
            
            confirmationID.topAnchor.constraint(equalTo: confirmCard.topAnchor, constant: 16),
            confirmationID.centerXAnchor.constraint(equalTo: confirmCard.centerXAnchor),
            
            dateLabel.topAnchor.constraint(equalTo: confirmationID.bottomAnchor, constant: 8),
            dateLabel.centerXAnchor.constraint(equalTo: confirmCard.centerXAnchor),
            dateLabel.bottomAnchor.constraint(equalTo: confirmCard.bottomAnchor, constant: -16),
            
            doneButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
            doneButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            doneButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            doneButton.heightAnchor.constraint(equalToConstant: 56),
            
            shareButton.bottomAnchor.constraint(equalTo: doneButton.topAnchor, constant: -12),
            shareButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
        ])
    }
    
    private func animateSuccess() {
        view.subviews.forEach { $0.alpha = 0; $0.transform = CGAffineTransform(translationX: 0, y: 20) }
        
        for (index, subview) in view.subviews.enumerated() {
            UIView.animate(withDuration: 0.5, delay: Double(index) * 0.1, usingSpringWithDamping: 0.8, initialSpringVelocity: 0, options: [], animations: {
                subview.alpha = 1
                subview.transform = .identity
            })
        }
        
        // Haptic feedback
        let generator = UINotificationFeedbackGenerator()
        generator.notificationOccurred(.success)
    }
    
    @objc private func done() {
        dismiss(animated: true) {
            // Navigate back to map
            if let tabBar = UIApplication.shared.windows.first?.rootViewController as? UITabBarController {
                tabBar.selectedIndex = 0
            }
        }
    }
}


